SELECT id, user_id, symbol, symbol_type, symbol_name,
       alert_date, time_point, change_percent, current_price,
       yesterday_close, is_read, triggered_at, created_at, updated_at,
       status, max_change_percent, min_change_percent, latest_detail_id, alert_type
FROM risk_alert
WHERE user_id = #{userId}

    AND triggered_at < #{cursor}

ORDER BY triggered_at DESC
LIMIT #{limit}

SELECT id, user_id, symbol, symbol_type, symbol_name,
       alert_date, time_point, change_percent, current_price,
       yesterday_close, is_read, triggered_at, created_at, updated_at,
       status, max_change_percent, min_change_percent, latest_detail_id, alert_type
FROM risk_alert
WHERE user_id = #{userId}
AND symbol = #{symbol}
AND triggered_at >= #{date}
ORDER BY triggered_at DESC
LIMIT 1

SELECT id, user_id, symbol, symbol_type, symbol_name,
       alert_date, time_point, change_percent, current_price,
       yesterday_close, is_read, triggered_at, created_at, updated_at,
       status, max_change_percent, min_change_percent, latest_detail_id, alert_type
FROM risk_alert
WHERE user_id = #{userId}
AND symbol = #{symbol}
AND triggered_at::date = #{alertDate}
LIMIT 1

SELECT id, user_id, symbol, symbol_type, symbol_name,
       alert_date, time_point, change_percent, current_price,
       yesterday_close, is_read, triggered_at, created_at, updated_at,
       status, max_change_percent, min_change_percent, latest_detail_id, alert_type
FROM risk_alert
WHERE user_id = #{userId}

    AND triggered_at::date >= #{startDate}


    AND triggered_at::date <= #{endDate}

ORDER BY


        triggered_at DESC


        id DESC


LIMIT #{size} OFFSET #{page}

SELECT COUNT(*) FROM risk_alert
WHERE user_id = #{userId}

    AND triggered_at::date >= #{startDate}


    AND triggered_at::date <= #{endDate}
